-- Seed courses 4-8 (approach A) into the Kurser category, sv/en/es.
INSERT INTO public.training_items
  (category_id, title, title_en, title_es, body, body_en, body_es, sort_order, is_published)
SELECT cat.id, v.title, v.title_en, v.title_es, v.body, v.body_en, v.body_es, v.ord, true
FROM (VALUES
  ('Mötesbokning & kalla samtal', 'Booking meetings & cold calls', 'Agendar reuniones y llamadas en frío', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mål: "}, {"type": "text", "text": "Fyll kalendern med kvalificerade möten – med rätt mindset, ett vasst manus och bra uppföljning."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Mindset"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "ringa utan att vara rädd för nej."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Målet med ett kallt samtal är inte att sälja – det är att boka mötet. Ett nej är inte personligt, det är statistik. Ju fler samtal, desto fler möten. Le när du ringer, det hörs."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Tänk \"nästa\" efter ett nej istället för att gruva dig."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Sätt ett mål: X samtal per dag, oavsett utfall."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – Öppningen & kroken"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "fånga uppmärksamheten på 30 sekunder."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Säg vem du är, var kort och be om 30 sekunder. Följ med en konkret krok om deras bransch eller sajt. Avsluta öppningen med en fråga, inte en monolog."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Hej [namn], [ditt namn] från Applabbet. Jag stör mitt i något – ge mig 30 sekunder så får du säga om det är intressant?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv din egen 30-sekundersöppning och säg den högt tio gånger."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Hantera \"skicka info\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "behålla initiativet vid artiga avfärdningar."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "\"Skicka info\" är ofta ett vänligt nej. Acceptera men kvalificera: fråga vad som är viktigast för dem, så blir materialet relevant – och boka en kort återkoppling så du behåller initiativet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Absolut – vad är viktigast just nu: fler kunder, modernare sajt eller bättre synlighet? Så skickar jag rätt sak och stämmer av på fredag.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv ditt svar på \"skicka info så återkommer vi\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Boka mötet & följ upp"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "stänga samtalet med en bokad tid."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Föreslå två konkreta tider istället för en öppen fråga. Bekräfta tiden i kalender och mail direkt. Följ upp uteblivna svar – de flesta möten bokas på andra eller tredje försöket."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Passar tisdag 10 eller torsdag 14?\" – lättare att svara på än \"när passar det?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Boka tre möten den här veckan och logga dem i CRM:t."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Goal: "}, {"type": "text", "text": "Fill your calendar with qualified meetings – with the right mindset, a sharp script and good follow-up."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 1 – Mindset"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to call without fearing a no."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "The goal of a cold call isn't to sell – it's to book the meeting. A no isn't personal, it's statistics. More calls, more meetings. Smile when you call, it shows."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Think \"next\" after a no instead of dwelling."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Set a goal: X calls a day, regardless of outcome."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 2 – The opening & the hook"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to grab attention in 30 seconds."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Say who you are, keep it short and ask for 30 seconds. Follow with a concrete hook about their industry or site. End the opening with a question, not a monologue."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Hi [name], [your name] from Applabbet. I'm interrupting something – give me 30 seconds and you tell me if it's interesting?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write your own 30-second opening and say it out loud ten times."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 3 – Handling \"send info\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to keep the initiative on polite brush-offs."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "\"Send info\" is often a friendly no. Accept but qualify: ask what matters most to them so the material is relevant – and book a short follow-up so you keep the initiative."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Absolutely – what matters most right now: more customers, a modern site or better visibility? Then I'll send the right thing and check in Friday.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write your answer to \"send info and we'll get back to you\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 4 – Book the meeting & follow up"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to close the call with a booked time."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Offer two concrete times instead of an open question. Confirm the time in the calendar and by email right away. Follow up on no-replies – most meetings are booked on the second or third attempt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Does Tuesday at 10 or Thursday at 2 work?\" – easier to answer than \"when suits you?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Book three meetings this week and log them in the CRM."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Meta: "}, {"type": "text", "text": "Llena tu agenda de reuniones cualificadas: con la mentalidad correcta, un guion afilado y un buen seguimiento."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 1 – Mentalidad"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a llamar sin miedo al no."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "El objetivo de una llamada en frío no es vender, es conseguir la reunión. Un no no es personal, es estadística. Más llamadas, más reuniones. Sonríe al llamar, se nota."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Piensa \"siguiente\" tras un no en vez de darle vueltas."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Fíjate una meta: X llamadas al día, pase lo que pase."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 2 – La apertura y el gancho"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a captar la atención en 30 segundos."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Di quién eres, sé breve y pide 30 segundos. Sigue con un gancho concreto sobre su sector o web. Termina la apertura con una pregunta, no un monólogo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Hola [nombre], [tu nombre] de Applabbet. Te interrumpo: dame 30 segundos y me dices si te interesa.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe tu apertura de 30 segundos y dila en voz alta diez veces."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 3 – Manejar \"envía info\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a mantener la iniciativa ante rechazos corteses."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "\"Envía info\" suele ser un no amable. Acepta pero cualifica: pregunta qué les importa más para que el material sea relevante, y agenda un breve seguimiento para mantener la iniciativa."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Claro: ¿qué es lo más importante ahora: más clientes, una web moderna o más visibilidad? Te mando lo adecuado y lo vemos el viernes.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe tu respuesta a \"envía info y os contactamos\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 4 – Agenda la reunión y haz seguimiento"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a cerrar la llamada con una hora agendada."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Ofrece dos horas concretas en vez de una pregunta abierta. Confirma la hora en el calendario y por correo enseguida. Haz seguimiento de los que no responden: la mayoría de reuniones se agendan al segundo o tercer intento."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Te va el martes a las 10 o el jueves a las 14?\": más fácil de responder que \"¿cuándo te viene bien?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Agenda tres reuniones esta semana y regístralas en el CRM."}]}]}$j$::jsonb, 4),
  ('Digital spetskunskap: SEO & GEO', 'Digital expertise: SEO & GEO', 'Conocimiento digital: SEO y GEO', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mål: "}, {"type": "text", "text": "Förstå och sälja SEO och GEO – de tjänster som ger återkommande intäkt och syns svart på vitt i rapporter."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Så funkar SEO"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "förklara SEO enkelt för en kund."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "SEO gör att en sajt rankar högre på Google. Det bygger på on-page (titlar, innehåll, fart), content och länkar. Det är långsiktigt – resultat på 3–6 månader – men trafiken kostar inget per klick."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Era kunder googlar redan det ni säljer – SEO avgör om de hittar er eller konkurrenten.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Förklara SEO för en kollega på 30 sekunder."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – Vad är GEO?"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "förklara AI-synlighet och varför det är nytt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "GEO handlar om att synas och rekommenderas i AI-sök som ChatGPT och Perplexity. Allt fler frågar AI istället för Google. Syns ni inte där finns ni inte i svaret. Konkurrenterna är oftast inte med än – det är försprånget."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Hur beskriver ChatGPT ert företag idag? Om svaret är tomt är det en möjlighet.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Fråga ChatGPT om en bransch och se vilka som nämns."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Mätbarhet & rapporter"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "använda siffror för att bygga förtroende."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Det som mäts går att sälja. Visa ranking, trafik och leads i månadsrapporten. Mätbarheten är ditt bästa motargument mot skepsis – det är inte löften, det är data."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Varje månad ser ni svart på vitt hur ni klättrar och hur många leads det gav.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Lista tre nyckeltal du kan visa en kund."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Sälj nuläge → potential"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "skapa köplust med en enkel analys."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Börja med en kostnadsfri synlighetsanalys: visa var de rankar idag och var de kan vara om tre månader. Glappet mellan nu och potential är säljargumentet. Avsluta med ett konkret nästa steg."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Ni ligger på sida två på ert viktigaste sökord – här är planen för att nå topp tre.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Gör en snabb synlighetskoll på ett företag och formulera potentialen."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Goal: "}, {"type": "text", "text": "Understand and sell SEO and GEO – the services that bring recurring revenue and show up in black and white in reports."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 1 – How SEO works"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to explain SEO simply to a customer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "SEO makes a site rank higher on Google. It's built on on-page (titles, content, speed), content and links. It's long-term – results in 3–6 months – but the traffic costs nothing per click."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Your customers already google what you sell – SEO decides whether they find you or the competitor.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Explain SEO to a colleague in 30 seconds."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 2 – What is GEO?"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to explain AI visibility and why it's new."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "GEO is about being seen and recommended in AI search like ChatGPT and Perplexity. More and more people ask AI instead of Google. If you're not there, you're not in the answer. Competitors usually aren't there yet – that's the head start."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"How does ChatGPT describe your company today? If the answer is blank, that's an opportunity.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Ask ChatGPT about an industry and see who's mentioned."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 3 – Measurability & reports"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to use numbers to build trust."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "What gets measured can be sold. Show ranking, traffic and leads in the monthly report. Measurability is your best counter to skepticism – it's not promises, it's data."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Every month you see in black and white how you climb and how many leads it produced.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "List three metrics you can show a customer."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 4 – Sell current state → potential"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to create desire with a simple analysis."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Start with a free visibility analysis: show where they rank today and where they could be in three months. The gap between now and potential is the sales argument. End with a concrete next step."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"You're on page two for your most important keyword – here's the plan to reach the top three.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Do a quick visibility check on a company and frame the potential."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Meta: "}, {"type": "text", "text": "Entiende y vende SEO y GEO: los servicios que generan ingresos recurrentes y se ven negro sobre blanco en los informes."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 1 – Cómo funciona el SEO"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a explicar el SEO de forma sencilla a un cliente."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "El SEO hace que una web posicione más alto en Google. Se basa en on-page (títulos, contenido, velocidad), contenido y enlaces. Es a largo plazo —resultados en 3–6 meses— pero el tráfico no cuesta nada por clic."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Tus clientes ya buscan lo que vendes en Google: el SEO decide si te encuentran a ti o al competidor.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Explica el SEO a un compañero en 30 segundos."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 2 – ¿Qué es el GEO?"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a explicar la visibilidad en IA y por qué es nueva."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "El GEO trata de aparecer y ser recomendado en buscadores de IA como ChatGPT y Perplexity. Cada vez más gente pregunta a la IA en vez de a Google. Si no estás ahí, no estás en la respuesta. Los competidores normalmente aún no están: esa es la ventaja."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Cómo describe ChatGPT tu empresa hoy? Si la respuesta está vacía, es una oportunidad.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Pregunta a ChatGPT por un sector y mira a quién menciona."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 3 – Medición e informes"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a usar números para generar confianza."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Lo que se mide se puede vender. Muestra ranking, tráfico y leads en el informe mensual. La medición es tu mejor argumento contra el escepticismo: no son promesas, son datos."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Cada mes ves negro sobre blanco cómo subes y cuántos leads generó.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Enumera tres métricas que puedes mostrar a un cliente."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 4 – Vende situación actual → potencial"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a crear deseo con un análisis simple."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Empieza con un análisis de visibilidad gratuito: muestra dónde posicionan hoy y dónde podrían estar en tres meses. La brecha entre el ahora y el potencial es el argumento de venta. Termina con un siguiente paso concreto."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Estáis en la segunda página de vuestra palabra clave más importante: este es el plan para llegar al top tres.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Haz una comprobación rápida de visibilidad de una empresa y formula el potencial."}]}]}$j$::jsonb, 5),
  ('Produktmästaren', 'The product master', 'El maestro de producto', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mål: "}, {"type": "text", "text": "Kunna alla paket utantill och snabbt matcha rätt lösning mot kundens behov och budget."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Hemsidor & appar"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "skilja på landningssida, hemsida, MVP, webbapp och mobilapp."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Landningssida (från 9 000 kr) för en kampanj, företagshemsida (18 000 kr) för närvaro, MVP (från 29 000 kr) för att validera, webbapp (från 49 000 kr) för funktionalitet, mobilapp (från 79 000 kr) för fickan. Matcha mot behovet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Behöver kunden inloggning och data? Då är det webbapp, inte hemsida."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Para ihop fem kundbehov med rätt produkt."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – E-handel"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "välja rätt e-handelsnivå."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Start (från 19 000 kr + 1 490 kr/mån) för få produkter, Plus (från 35 000 kr + 2 490 kr/mån) för växande butiker, Pro (från 59 000 kr + 4 900 kr/mån) för stora kataloger, B2B och ERP. Välj efter sortiment och integrationsbehov."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Behöver de Fortnox-koppling och B2B-priser? Då är det Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Motivera vilken nivå tre olika butiker borde ha."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – SEO, GEO & design"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "sälja de löpande tjänsterna."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "SEO (från 4 900 kr/mån) och GEO (från 6 900 kr/mån) ger synlighet och återkommande intäkt. Designpartner (från 9 000 kr/mån) ger löpande design. Logotyp & varumärke (från 12 000 kr) är en bra dörröppnare."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Efter en levererad hemsida är SEO/GEO den naturliga uppföljningen."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Föreslå en löpande tjänst till tre tidigare kunder."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Kombinationer & paket"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "öka affären med smarta kombinationer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Paketera ihop tjänster: Startpaket (hemsida + SEO), Tillväxtpaket (hemsida + SEO + GEO), MVP-paket (MVP + designpartner). Kombinationer höjer ordervärdet och ger kunden en helhet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Vill ni både synas och konvertera från dag ett? Då är Startpaketet rätt.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Sätt ihop ett eget paket för en påhittad kund."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Goal: "}, {"type": "text", "text": "Know every package by heart and quickly match the right solution to the customer's need and budget."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 1 – Websites & apps"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to tell apart a landing page, website, MVP, web app and mobile app."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Landing page (from SEK 9,000) for a campaign, business website (SEK 18,000) for presence, MVP (from SEK 29,000) to validate, web app (from SEK 49,000) for functionality, mobile app (from SEK 79,000) for the pocket. Match to the need."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Does the customer need login and data? Then it's a web app, not a website."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Match five customer needs with the right product."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 2 – E-commerce"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to choose the right e-commerce tier."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Start (from SEK 19,000 + SEK 1,490/mo) for few products, Plus (from SEK 35,000 + SEK 2,490/mo) for growing stores, Pro (from SEK 59,000 + SEK 4,900/mo) for large catalogues, B2B and ERP. Choose by range and integration needs."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Do they need a Fortnox connection and B2B pricing? Then it's Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Justify which tier three different stores should have."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 3 – SEO, GEO & design"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to sell the recurring services."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "SEO (from SEK 4,900/mo) and GEO (from SEK 6,900/mo) give visibility and recurring revenue. A design partner (from SEK 9,000/mo) gives ongoing design. Logo & brand (from SEK 12,000) is a great door-opener."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "After a delivered website, SEO/GEO is the natural follow-up."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Propose a recurring service to three past customers."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 4 – Combinations & bundles"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to grow the deal with smart combinations."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Bundle services: Starter bundle (website + SEO), Growth bundle (website + SEO + GEO), MVP bundle (MVP + design partner). Combinations raise the order value and give the customer a whole."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Want to both be seen and convert from day one? Then the Starter bundle is right.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Put together your own bundle for an imagined customer."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Meta: "}, {"type": "text", "text": "Conoce todos los paquetes de memoria y empareja rápido la solución adecuada con la necesidad y el presupuesto del cliente."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 1 – Webs y apps"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a distinguir página de aterrizaje, web, MVP, app web y app móvil."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Página de aterrizaje (desde 9 000 SEK) para una campaña, web corporativa (18 000 SEK) para presencia, MVP (desde 29 000 SEK) para validar, app web (desde 49 000 SEK) para funcionalidad, app móvil (desde 79 000 SEK) para el bolsillo. Empareja con la necesidad."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "¿El cliente necesita inicio de sesión y datos? Entonces es una app web, no una web."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Empareja cinco necesidades de cliente con el producto adecuado."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 2 – E-commerce"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a elegir el nivel de e-commerce adecuado."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Start (desde 19 000 SEK + 1 490 SEK/mes) para pocos productos, Plus (desde 35 000 SEK + 2 490 SEK/mes) para tiendas en crecimiento, Pro (desde 59 000 SEK + 4 900 SEK/mes) para catálogos grandes, B2B y ERP. Elige según catálogo y necesidades de integración."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "¿Necesitan conexión con Fortnox y precios B2B? Entonces es Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Justifica qué nivel deberían tener tres tiendas distintas."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 3 – SEO, GEO y diseño"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a vender los servicios recurrentes."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "SEO (desde 4 900 SEK/mes) y GEO (desde 6 900 SEK/mes) dan visibilidad e ingresos recurrentes. Un socio de diseño (desde 9 000 SEK/mes) da diseño continuo. Logotipo y marca (desde 12 000 SEK) es un buen abrepuertas."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Tras entregar una web, el SEO/GEO es el seguimiento natural."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Propón un servicio recurrente a tres clientes anteriores."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 4 – Combinaciones y paquetes"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a aumentar la venta con combinaciones inteligentes."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Empaqueta servicios: Paquete inicial (web + SEO), Paquete de crecimiento (web + SEO + GEO), Paquete MVP (MVP + socio de diseño). Las combinaciones suben el valor del pedido y dan al cliente un conjunto."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Queréis aparecer y convertir desde el primer día? Entonces el Paquete inicial es el adecuado.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Crea tu propio paquete para un cliente imaginario."}]}]}$j$::jsonb, 6),
  ('Storytelling & pitch', 'Storytelling & pitch', 'Storytelling y pitch', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mål: "}, {"type": "text", "text": "Bygga en pitch som inger förtroende och får kunden att tänka \"jag måste ha detta\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Problem → lösning → resultat"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "strukturera en pitch som fastnar."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Börja i kundens problem, visa lösningen, måla resultatet. Människor minns berättelser, inte funktionslistor. Sälj förändringen – från hur det är nu till hur det blir."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Idag tappar ni kunder till en snabbare sajt. Med en ny hemsida vänder vi det – fler förfrågningar redan första månaden.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv en pitch i tre meningar enligt problem–lösning–resultat."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – Använd kundens egna ord"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "skräddarsy pitchen efter behovsanalysen."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Den bästa pitchen ekar det kunden själv sagt. Anteckna nyckelord i mötet och spegla tillbaka dem. Då känner kunden sig förstådd och pitchen känns gjord för dem."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Du sa att tid är er flaskhals – det här tar bort det manuella jobbet.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Ta tre kundcitat och bygg en mening kring varje."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Konkreta exempel & bevis"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "göra värdet trovärdigt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Abstrakta löften övertygar ingen. Använd siffror, exempel och referenser. \"En extra kund i månaden betalar sajten\" slår \"det blir bra\". Visa hellre än berätta."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"En liknande kund gick från sida två till topp tre på tre månader.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Hitta tre konkreta bevis du kan använda i en pitch."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Avsluta med en fråga"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "föra pitchen mot ett nästa steg."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Avsluta aldrig en pitch med tystnad – avsluta med en fråga som öppnar för nästa steg. Det håller samtalet levande och visar att du leder. Frågan ska vara lätt att säga ja till."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Ska jag ta fram ett förslag så går vi igenom det tillsammans på fredag?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv tre avslutsfrågor som leder mot ett möte eller offert."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Goal: "}, {"type": "text", "text": "Build a pitch that inspires trust and makes the customer think \"I must have this\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 1 – Problem → solution → result"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to structure a pitch that sticks."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Start in the customer's problem, show the solution, paint the result. People remember stories, not feature lists. Sell the change – from how it is now to how it'll be."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Today you lose customers to a faster site. With a new website we turn that around – more enquiries the very first month.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write a three-sentence pitch using problem–solution–result."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 2 – Use the customer's own words"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to tailor the pitch to the needs analysis."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "The best pitch echoes what the customer said themselves. Note keywords in the meeting and mirror them back. Then the customer feels understood and the pitch feels made for them."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"You said time is your bottleneck – this removes the manual work.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Take three customer quotes and build a sentence around each."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 3 – Concrete examples & proof"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to make the value credible."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Abstract promises convince no one. Use numbers, examples and references. \"One extra customer a month pays for the site\" beats \"it'll be great\". Show rather than tell."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"A similar customer went from page two to the top three in three months.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Find three concrete proofs you can use in a pitch."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 4 – End with a question"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to move the pitch toward a next step."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Never end a pitch with silence – end with a question that opens the next step. It keeps the conversation alive and shows you're leading. The question should be easy to say yes to."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Shall I prepare a proposal and we go through it together on Friday?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write three closing questions that lead toward a meeting or quote."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Meta: "}, {"type": "text", "text": "Construye un pitch que inspire confianza y haga que el cliente piense \"tengo que tener esto\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 1 – Problema → solución → resultado"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a estructurar un pitch que se quede."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Empieza en el problema del cliente, muestra la solución, pinta el resultado. La gente recuerda historias, no listas de funciones. Vende el cambio: de cómo es ahora a cómo será."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Hoy perdéis clientes ante una web más rápida. Con una web nueva lo revertimos: más solicitudes ya el primer mes.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe un pitch de tres frases con problema–solución–resultado."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 2 – Usa las palabras del cliente"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a adaptar el pitch al análisis de necesidades."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "El mejor pitch repite lo que el cliente dijo. Anota palabras clave en la reunión y refléjalas. Así el cliente se siente comprendido y el pitch parece hecho para él."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Dijiste que el tiempo es vuestro cuello de botella: esto elimina el trabajo manual.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Toma tres citas del cliente y construye una frase con cada una."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 3 – Ejemplos concretos y pruebas"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a hacer creíble el valor."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Las promesas abstractas no convencen a nadie. Usa números, ejemplos y referencias. \"Un cliente extra al mes paga la web\" supera a \"quedará genial\". Muestra en vez de contar."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Un cliente parecido pasó de la segunda página al top tres en tres meses.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Encuentra tres pruebas concretas para usar en un pitch."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 4 – Termina con una pregunta"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a llevar el pitch hacia un siguiente paso."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Nunca termines un pitch en silencio: termina con una pregunta que abra el siguiente paso. Mantiene viva la conversación y muestra que tú diriges. La pregunta debe ser fácil de responder con un sí."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Preparo una propuesta y la repasamos juntos el viernes?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe tres preguntas de cierre que lleven a una reunión o presupuesto."}]}]}$j$::jsonb, 7),
  ('CRM-mästaren', 'The CRM master', 'El maestro del CRM', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mål: "}, {"type": "text", "text": "Jobba effektivt i CRM:t så att ingen affär faller mellan stolarna – alltid med ett tydligt nästa steg."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Lägg in & jobba leads"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "skapa och underhålla leads rätt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Skapa en lead så fort du ser en möjlighet – med företagsnamn, kontakt och din observation. En lead som inte finns i CRM:t glöms bort. Uppdatera status löpande."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Direkt efter ett samtal: logga vad som sades och nästa steg."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Lägg in fem leads och fyll i alla fält ordentligt."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – Uppgifter & möten"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "använda CRM:t för att aldrig tappa en tråd."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Lägg en uppgift eller boka ett möte för varje lead. Sätt datum så systemet påminner dig. Det är skillnaden mellan att jaga och att ha kontroll."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Lovade du återkomma på fredag? Lägg en uppgift direkt så glöms det inte."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skapa en uppgift för varje aktiv lead du har."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Alltid ett nästa steg"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "hålla varje affär i rörelse."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "En lead utan nästa steg dör. Avsluta varje kontakt med att boka nästa: ett möte, en återkoppling, en offert. Pipeline är inte en lista – det är affärer i rörelse."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Innan du avslutar ett samtal: \"Nästa steg är… ska vi säga [datum]?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Gå igenom din pipeline och säkerställ att varje lead har ett nästa steg."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Öva i Sandbox"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "testa funktioner utan risk."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Osäker på hur något fungerar? Sandbox-fliken är en kopia av CRM:t där inget sparas. Klicka runt, prova, lär dig – sen kör du skarpt med säkra händer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Innan du skickar ditt första mail på riktigt: testa flödet i Sandbox."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Gå igenom varje flik i Sandbox en gång."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Goal: "}, {"type": "text", "text": "Work effectively in the CRM so no deal slips through the cracks – always with a clear next step."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 1 – Add & work leads"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to create and maintain leads properly."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Create a lead as soon as you spot an opportunity – with company name, contact and your observation. A lead that's not in the CRM gets forgotten. Update the status continuously."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Right after a call: log what was said and the next step."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Add five leads and fill in every field properly."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 2 – Tasks & meetings"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to use the CRM so you never lose a thread."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Add a task or book a meeting for every lead. Set a date so the system reminds you. It's the difference between chasing and being in control."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Promised to get back on Friday? Add a task right away so it's not forgotten."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Create a task for every active lead you have."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 3 – Always a next step"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to keep every deal moving."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "A lead with no next step dies. End every contact by booking the next one: a meeting, a follow-up, a quote. A pipeline isn't a list – it's deals in motion."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Before you end a call: \"The next step is… shall we say [date]?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Go through your pipeline and make sure every lead has a next step."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 4 – Practise in Sandbox"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to test features risk-free."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Unsure how something works? The Sandbox tab is a copy of the CRM where nothing is saved. Click around, try, learn – then go live with confidence."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Before you send your first email for real: test the flow in Sandbox."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Go through every tab in Sandbox once."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Meta: "}, {"type": "text", "text": "Trabaja con eficacia en el CRM para que ninguna venta se pierda: siempre con un siguiente paso claro."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 1 – Añade y trabaja leads"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a crear y mantener leads correctamente."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Crea un lead en cuanto veas una oportunidad: con nombre de empresa, contacto y tu observación. Un lead que no está en el CRM se olvida. Actualiza el estado de forma continua."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Justo tras una llamada: registra lo que se dijo y el siguiente paso."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Añade cinco leads y rellena bien cada campo."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 2 – Tareas y reuniones"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a usar el CRM para no perder nunca un hilo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Añade una tarea o agenda una reunión para cada lead. Pon fecha para que el sistema te recuerde. Es la diferencia entre perseguir y tener el control."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "¿Prometiste contactar el viernes? Añade una tarea enseguida para no olvidarlo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Crea una tarea para cada lead activo que tengas."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 3 – Siempre un siguiente paso"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a mantener cada venta en movimiento."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Un lead sin siguiente paso muere. Termina cada contacto agendando el siguiente: una reunión, un seguimiento, un presupuesto. Un pipeline no es una lista: son ventas en movimiento."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Antes de terminar una llamada: \"El siguiente paso es… ¿decimos [fecha]?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Revisa tu pipeline y asegúrate de que cada lead tenga un siguiente paso."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 4 – Practica en Sandbox"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a probar funciones sin riesgo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "¿No sabes cómo funciona algo? La pestaña Sandbox es una copia del CRM donde no se guarda nada. Haz clic, prueba, aprende, y luego trabaja en real con seguridad."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Antes de enviar tu primer correo de verdad: prueba el flujo en Sandbox."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Recorre cada pestaña de Sandbox una vez."}]}]}$j$::jsonb, 8)
) AS v(title, title_en, title_es, body, body_en, body_es, ord)
JOIN public.training_categories cat ON cat.slug = 'kurser'
WHERE NOT EXISTS (
  SELECT 1 FROM public.training_items ti
  WHERE ti.category_id = cat.id AND ti.title = v.title
);
